module.render:
const esc = (s) => String(s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');
const color = args.color || 'var(--accent-color)';
const pts = [];
sections.join('\n').split('\n').map((l) => l.trim()).filter(Boolean).forEach((l) => {
  const m = l.match(/^(-?[\d.]+)[\s,]+(-?[\d.]+)\s*([\s\S]*)$/);
  if (m) pts.push({ x: parseFloat(m[1]), y: parseFloat(m[2]), label: m[3].trim() });
});
if (pts.length < 2) return `<div>(scatter: at least two "x y" lines)</div>`;
let xlo = Math.min(...pts.map((p) => p.x)), xhi = Math.max(...pts.map((p) => p.x));
let ylo = Math.min(...pts.map((p) => p.y)), yhi = Math.max(...pts.map((p) => p.y));
if (xhi === xlo) { xhi += 1; xlo -= 1; }
if (yhi === ylo) { yhi += 1; ylo -= 1; }
const padX = (xhi - xlo) * 0.08, padY = (yhi - ylo) * 0.1;
xlo -= padX; xhi += padX; ylo -= padY; yhi += padY;
const W = 160, H = 100;
const gx = (x) => ((x - xlo) / (xhi - xlo)) * W;
const gy = (y) => H - ((y - ylo) / (yhi - ylo)) * H;
const f = (v) => v.toFixed(1);
let svg = `<rect x="0" y="0" width="${W}" height="${H}" class="mdp-sc-frame"/>`;
let caption = '';
if (String(args.trend) === 'true') {
  const n = pts.length;
  const sx = pts.reduce((a, p) => a + p.x, 0), sy = pts.reduce((a, p) => a + p.y, 0);
  const sxx = pts.reduce((a, p) => a + p.x * p.x, 0), sxy = pts.reduce((a, p) => a + p.x * p.y, 0);
  const den = n * sxx - sx * sx;
  if (den !== 0) {
    const a = (n * sxy - sx * sy) / den, b = (sy - a * sx) / n;
    const my = sy / n;
    const ssRes = pts.reduce((acc, p) => acc + Math.pow(p.y - (a * p.x + b), 2), 0);
    const ssTot = pts.reduce((acc, p) => acc + Math.pow(p.y - my, 2), 0) || 1;
    const r2 = 1 - ssRes / ssTot;
    svg += `<line x1="${f(gx(xlo))}" y1="${f(gy(a * xlo + b))}" x2="${f(gx(xhi))}" y2="${f(gy(a * xhi + b))}" class="mdp-sc-trend"/>`;
    caption = `<div class="mdp-sc-eq">y = ${+a.toFixed(4)}x ${b >= 0 ? '+' : '−'} ${Math.abs(+b.toFixed(4))} &nbsp; r² = ${+r2.toFixed(3)}</div>`;
  }
}
pts.forEach((p) => {
  svg += `<circle cx="${f(gx(p.x))}" cy="${f(gy(p.y))}" r="2" class="mdp-sc-pt"/>`;
  if (p.label) svg += `<text x="${f(gx(p.x) + 3)}" y="${f(gy(p.y) - 3)}" class="mdp-sc-lbl">${esc(p.label)}</text>`;
});
let axes = '';
if (args.xlabel) axes += `<div class="mdp-sc-xlabel">${esc(args.xlabel)}</div>`;
let html = `\n\n<div class="mdp-mod-scatter" style="--sc-c:${color};">`;
if (args.ylabel) html += `<div class="mdp-sc-ylabel">${esc(args.ylabel)}</div>`;
html += `<div class="mdp-sc-plotwrap"><svg viewBox="0 0 ${W} ${H}" preserveAspectRatio="xMidYMid meet">${svg}</svg>${axes}${caption}</div></div>\n\n`;
return html;
